#include <stdio.h>

int main() {
  for (int i = 2; i <= 10; i += 2) {
    printf("Even number: %d\n", i);
  }
  return 0;
}
// Output:
// Even number: 2
// Even number: 4
// Even number: 6
// Even number: 8
// Even number: 10

#include <stdio.h>

int main() {
  for (int i = 1; i <= 15; i++) {
    if (i % 3 == 0) {
      printf("Divisible by 3: %d\n", i);
    }
  }
  return 0;
}
// Output:
// Divisible by 3: 3
// Divisible by 3: 6
// Divisible by 3: 9
// Divisible by 3: 12
// Divisible by 3: 15

